```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <stdio.h>

int main() {
    int pipefd[2];  // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    pid_t pid = fork();  // Fork a new process

    if (pid == -1) {
        perror("fork");
        return 1;
    }

    if (pid == 0) {  // Child process
        // Close the write end of the pipe in the child
        close(pipefd[1]);

        // Duplicate the read end of the pipe to standard input and output
        dup2(pipefd[0], STDIN_FILENO);
        dup2(pipefd[0], STDOUT_FILENO);

        // Close the pipe file descriptors
        close(pipefd[0]);

        // Execute a command, for example, a shell
        execlp("/bin/sh", "sh", "-c", "echo 'Hello from child process!'", (char *)NULL);
        perror("execlp");  // If execlp fails
        return 1;
    } else {  // Parent process
        // Close the read end of the pipe in the parent
        close(pipefd[0]);

        // Write some data to the pipe
        const char *message = "Hello from parent process!";
        write(pipefd[1], message, strlen(message));

        // Close the write end of the pipe
        close(pipefd[1]);

        // Wait for the child to finish
        wait(NULL);

        std::cout << "Parent process received: " << std::flush;
        char buffer[100];
        read(pipefd[0], buffer, sizeof(buffer));
        std::cout << buffer << std::endl;

        // Close the read end of the pipe
        close(pipefd[0]);
    }

    return 0;
}
```

